<?php
namespace App\Modules\Drivers\Application\Services;
use App\Models\ActivityLog; use App\Models\Trip; use App\Modules\Drivers\Application\StateMachines\DriverTripStateMachine; use App\Modules\Realtime\Domain\Events\TripStatusUpdated; use App\Support\Observability\CorrelationContext;
final class DriverTripService { public function __construct(private readonly DriverTripStateMachine $states, private readonly TripTimelineService $timeline) {} public function acceptTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::ACCEPTED,'driver_accepted'); } public function rejectTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::CANCELLED,'trip_cancelled'); } public function startTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::STARTED,'driver_started'); } public function pauseTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::PICKUP,'pickup_reached'); } public function resumeTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::ON_ROUTE,'on_route'); } public function finishTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::COMPLETED,'trip_finished'); } public function cancelTrip(Trip $trip): Trip { return $this->move($trip,DriverTripStateMachine::CANCELLED,'trip_cancelled'); } private function move(Trip $trip,string $to,string $event): Trip { $from=$trip->status ?: DriverTripStateMachine::READY; $trip->forceFill(['status'=>$this->states->transition($from,$to)])->save(); ActivityLog::create(['action'=>'trip.status.'.$to,'subject_type'=>Trip::class,'subject_id'=>$trip->id,'metadata'=>['from'=>$from,'to'=>$to,'trip_uuid'=>$trip->uuid,'correlation_id'=>CorrelationContext::correlationId()]]); $this->timeline->record($trip,$event,['from'=>$from,'to'=>$to]); event(new TripStatusUpdated((string)$trip->id,(string)($trip->booking_id ?? $trip->id),$to)); return $trip; }}
